#include <stdio.h>
int main() {
    int T, N, i, j;
    char S[1001], T[1001];
    scanf("%d", &T);
    while (T--) {
        scanf("%d %s", &N, S);
        int a = 0, b = N - 1;
        int p = 0;
        while (a <= b) {
            if (a == b) {
                T[p++] = S[a];
                break;
            }
            if (S[a] == '0' && S[b] == '1') {
                T[p++] = '0';
                a++;
            } else if (S[a] == '1' && S[b] == '0') {
                T[p++] = '1';
                b--;
            } else if (S[a] == '0' && S[b] == '0') {
                T[p++] = '0';
                a++;
            } else {
                T[p++] = '1';
                b--;
            }
        }
        T[p] = '\0';
        printf("%s\n", T);
    }
    return 0;
}

