import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            char[] S = sc.next().toCharArray();
            int a = 0, b = N - 1;
            int p = 0;
            char[] T = new char[N];
            while (a <= b) {
                if (a == b) {
                    T[p++] = S[a];
                    break;
                }
                if (S[a] == '0' && S[b] == '1') {
                    T[p++] = '0';
                    a++;
                } else if (S[a] == '1' && S[b] == '0') {
                    T[p++] = '1';
                    b--;
                } else if (S[a] == '0' && S[b] == '0') {
                    T[p++] = '0';
                    a++;
